148→    @Override
149→    public List<AnnouncementEntity> getExactAnnouncement() {
150→        GetExactAnnouncementRequest request = GetExactAnnouncementRequest.newBuilder().build();
151→        log.info("start getExactAnnouncement, 运行环境：{}", constProperties.isInternalNetwork());
152→        GetExactAnnouncementResult result = collabspaceMirrorStub.getExactAnnouncement(request);
153→        log.info("mirror获取待发公告, 运行环境：{}", constProperties.isInternalNetwork());
154→        List<GetListAnnouncementVo> voList = new ArrayList<>();
155→        result.getListList().forEach(
156→                val -> {
157→                    GetListAnnouncementVo vo = JSONUtil.toBean(val, GetListAnnouncementVo.class);
158→                    vo.setStatus(AnnouncementStatus.WAITING.getCode());
159→                    voList.add(vo);
160→                }
161→        );
162→        List<Long> currentIdList = voList.stream().map(GetListAnnouncementVo::getId).toList();
163→        // 2. 从Redis中获取历史上待发送的公告ID集合
164→        String redisKey = "announcement:historical_ids";
165→        List<Long> historicalIdList = new ArrayList<>();
166→        try {
167→            String historicalIdsJson = redisTemplate.opsForValue().get(redisKey);
168→            if (StringUtils.isNotBlank(historicalIdsJson)) {
169→                historicalIdList = JSONUtil.toList(historicalIdsJson, Long.class);
170→            }
171→            log.info("历史公告ID列表：{}", historicalIdList);
172→        } catch (Exception e) {
173→            log.warn("获取历史公告ID失败", e);
174→        }
175→
176→        // 3. 比较获取在历史中但不在当前中的公告ID集合（可能已发送或取消的）
177→        List<Long> missingIdList = historicalIdList.stream()
178→                .filter(id -> !currentIdList.contains(id))
179→                .toList();
180→
181→        if (!missingIdList.isEmpty()) {
182→            log.info("发现历史公告中缺失的ID：{}", missingIdList);
183→
184→            // 4. 去mirror中根据ID获取这部分公告详情
185→            try {
186→                GetAnnouncementRequest announcementRequest = GetAnnouncementRequest.newBuilder()
187→                        .addAllAnnouncementIdList(missingIdList).build();
188→                GetAnnouncementResult missingAnnouncements = collabspaceMirrorStub.getAnnouncementById(announcementRequest);
189→
190→                // 不要直接添加，需要确保状态正确
191→                missingAnnouncements.getListList().forEach(val -> {
192→                    GetListAnnouncementVo vo = JSONUtil.toBean(val, GetListAnnouncementVo.class);
193→                    // 这里不要设置 status，保留 mirror 返回的真实状态
194→                    // 如果 mirror 返回的状态为空，可以设置一个默认值
195→                    if (vo.getStatus() == null) {
196→                        vo.setStatus(AnnouncementStatus.PUBLISHED.getCode());
197→                    }
198→                    voList.add(vo);
199→                });
200→
201→            } catch (Exception e) {
202→                log.error("获取缺失公告详情失败", e);
203→            }
204→        }
205→
206→        // 更新Redis逻辑：当前ID + 历史ID - 缺失ID，去重后存储
207→        try {
208→            Set<Long> updatedIdSet = new HashSet<>();
209→            updatedIdSet.addAll(currentIdList);        // 添加当前ID
210→            updatedIdSet.addAll(historicalIdList);     // 添加历史ID
211→
212→            log.info("合并前ID数量：{}，当前ID：{}，历史ID：{}",
213→                    updatedIdSet.size(), currentIdList.size(), historicalIdList.size());
214→
215→            // 移除已处理的ID并记录移除结果
216→            int removedCount = 0;
217→            for (Long missingId : missingIdList) {
218→                if (updatedIdSet.remove(missingId)) {
219→                    removedCount++;
220→                }
221→            }
222→
223→            log.info("需要移除的ID数量：{}，实际移除的ID数量：{}", missingIdList.size(), removedCount);
224→
225→            List<Long> updatedIdList = new ArrayList<>(updatedIdSet);
226→
227→            if (!updatedIdList.isEmpty()) {
228→                redisTemplate.opsForValue().set(redisKey, JSONUtil.toJsonStr(updatedIdList), Duration.ofDays(7));
229→                log.info("已更新Redis中的历史公告ID列表，最新ID数量：{}", updatedIdList.size());
230→            } else {
231→                log.info("更新后ID列表为空，清空Redis");
232→                redisTemplate.delete(redisKey);
233→            }
234→        } catch (Exception e) {
235→            log.warn("更新Redis失败", e);
236→        }
237→        return transAnnouncementEntity(voList);
238→
239→    }
