 93→    @RabbitListener(queues = SPACE_NODE_MIGRATION_QUEUE)
 94→    public void handle(Message message, Channel channel) throws IOException {
 95→        String body = new String(message.getBody());
 96→        log.info("Received space node migration task message: {}", body);
 97→
 98→        SpaceNodeMigrationMessage messageDto = JSONUtil.toBean(body, SpaceNodeMigrationMessage.class);
 99→        String taskId = messageDto.getTaskId();
100→
101→        try {
102→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
103→            ExceptionUtil.isNotNull(task, DatabaseException.QUERY_EMPTY_BY_ID);
104→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.PROCESSING.getValue());
105→            spaceNodeMigrationTaskService.updateById(task);
106→
107→            executeTask(task);
108→
109→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.COMPLETED.getValue());
110→            spaceNodeMigrationTaskService.updateById(task);
111→
112→        } catch (Exception e) {
113→            log.error("Failed to process space node migration task: taskId={}, error={}", taskId, e.getMessage(), e);
114→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
115→            if (task != null) {
116→                task.setStatus(SpaceNodeMigrationTaskStatusEnum.FAILED.getValue());
117→                task.setErrorMessage(e.getMessage());
118→                spaceNodeMigrationTaskService.updateById(task);
119→            }
120→        } finally {
121→            // 先不考虑重试
122→            long deliveryTag = message.getMessageProperties().getDeliveryTag();
123→            channel.basicAck(deliveryTag, false);
124→        }
125→    }
