127→    private void executeTask(SpaceNodeMigrationTaskEntity task) throws IOException {
128→        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(task.getEmail());
129→        ExceptionUtil.isNotNull(user, SpaceNodeMigrationException.OPERATOR_NOT_EXIST);
130→        Long userId = user.getId();
131→        // 鉴权
132→        if (!spaceQueryManager.isUserSpaceAdmin(userId, task.getTargetSpaceId())) {
133→            throw new BusinessException(AuthException.UNAUTHORIZED);
134→        }
135→
136→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = deserializeTree(task.getOriginTree());
137→        List<SpaceAppRelVo> sourceSpaceAppRels = JSONUtil.toList(task.getSourceSpaceAppRels(), SpaceAppRelVo.class);
138→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(task.getType());
139→
140→        log.info("executeTask: taskId={}, treeSize={}, type: {}, appRels: {}", task.getTaskId(), spaceNodeTree.size(), migrationType.getDescription(), task.getSourceSpaceAppRels());
141→
142→        MigrationConfig migrationConfig = MigrationConfig.builder()
143→                .email(task.getEmail())
144→                .sourceSpaceAppRels(sourceSpaceAppRels)
145→                .build();
146→        
147→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
148→                spaceNodeTree, 
149→                task.getTargetSpaceId(),
150→                task.getSourceSpaceId(),
151→                migrationType, 
152→                migrationConfig
153→        );
154→        
155→        log.info("Overall migration completed: success={}, failed={}, total mappings={}", 
156→                overallResult.getSuccessCount(), overallResult.getFailedCount(), 
157→                overallResult.getNodeIdMapping().size());
158→
159→        // 迁移中遇到错误抛异常并终止迁移
160→        if (overallResult.getErrorMessage() != null) {
161→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
162→            throw new BusinessException(overallResult.getErrorMessage());
163→        }
164→
165→        // 迁移后的节点重新构建成树并入库
166→        saveNewNodeTree(spaceNodeTree, task.getTargetSpaceId(), overallResult.getNodeIdMapping(), userId, migrationType);
167→        // 判断是空间站内迁移并且保留状态是false，调用文件删除接口，把源文件删除
168→        if (!task.getIsRemained() && task.getType().equals(MigrationTypeEnum.INTRA_SERVER.getValue())) {
169→            for (TreeNode<SpaceNodeVo> treeNode : spaceNodeTree) {
170→                spaceNodeUpdateManager.deleteSpaceNode(treeNode.getRelId(), userId);
171→            }
172→        }
173→    }
