175→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping, Long userId, MigrationTypeEnum migrationType) {
176→        if (originalTree == null || originalTree.isEmpty()) {
177→            log.info("No tree nodes to save for space: {}", spaceId);
178→            return;
179→        }
180→
181→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
182→
183→        for (TreeNode<SpaceNodeVo> node : originalTree) {
184→            saveNodeAndChildren(node, spaceId, nodeIdMapping, ROOT_PARENT_ID, userId, migrationType);
185→        }
186→
187→        log.info("Completed saving new node tree for space: {}", spaceId);
188→    }
189→
190→    private String resolveUniqueName(String spaceId, String name, Long parentId) {
191→        if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, name, parentId)) {
192→            return name;
193→        }
194→        int count = 1;
195→        while (true) {
196→            String candidate = name + "(" + count + ")";
197→            if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, candidate, parentId)) {
198→                return candidate;
199→            }
200→            count++;
201→        }
202→    }
203→
204→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping, Long parentId, Long userId, MigrationTypeEnum migrationType) {
205→        SpaceNodeVo spaceNodeVo = node.getData();
206→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
207→        String newNodeId = nodeIdMapping.get(oldNodeId);
208→
209→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
210→            newNodeId = "";
211→        }
212→
213→        if (newNodeId == null) {
214→            log.error("No mapping found for node: {}", oldNodeId);
215→            return;
216→        }
217→
218→        String originalName = spaceNodeVo.getName();
219→        String name = MigrationTypeEnum.CROSS_SERVER.equals(migrationType)
220→                ? resolveUniqueName(spaceId, originalName, parentId)
221→                : originalName;
222→        if (!name.equals(originalName)) {
223→            log.info("[2010-change-filename] migrate node name conflict, renamed: [{}] -> [{}], spaceId: {}, " +
224→                            "parentId: {}",
225→                    originalName,
226→                    name, spaceId, parentId);
227→        }
228→
229→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
230→                .appSpaceNodeId(newNodeId)
231→                .name(name)
232→                .type(spaceNodeVo.getType())
233→                .description(spaceNodeVo.getDescription())
234→                .spaceId(spaceId)
235→                .createdBy(userId)
236→                .updatedBy(userId)
237→                .build();
238→
239→        spaceNodeService.save(spaceNodeEntity);
240→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
241→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
242→
243→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
244→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
245→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId, migrationType);
246→            }
247→        }
248→    }
