250→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
251→        ObjectMapper mapper = objectMapper.copy();
252→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
253→        SimpleModule module = new SimpleModule();
254→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
255→        mapper.registerModule(module);
256→        JavaType treeNodeType =
257→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
258→        JavaType listType =
259→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
260→        return mapper.readValue(json, listType);
261→    }
